import { renderHook } from "#test/browser"
import { useIdle } from "./"

describe("useIdle", () => {
  beforeEach(() => {
    vi.useFakeTimers()
  })

  afterEach(() => {
    vi.useRealTimers()
  })

  test("initial state is true", async () => {
    const { result } = await renderHook(() => useIdle(50))
    expect(result.current).toBeTruthy()
  })

  test("becomes true after specified time has elapsed following an event", async () => {
    const { act, result } = await renderHook(() => useIdle(100))

    await act(() => {
      document.dispatchEvent(new Event("mousemove"))
    })
    expect(result.current).toBeFalsy()

    await act(() => vi.advanceTimersByTime(100))

    expect(result.current).toBeTruthy()
  })

  test("is false while events are occurring", async () => {
    const { act, result } = await renderHook(() => useIdle(100))

    await act(() => {
      document.dispatchEvent(new Event("mousemove"))
    })
    expect(result.current).toBeFalsy()

    await act(() => {
      document.dispatchEvent(new Event("keypress"))
    })
    expect(result.current).toBeFalsy()
  })

  test("can detect idle state with custom events", async () => {
    const customEvents: (keyof DocumentEventMap)[] = ["mousedown", "wheel"]
    const { act, result } = await renderHook(() =>
      useIdle(50, { events: customEvents }),
    )

    await act(() => {
      document.dispatchEvent(new Event("mousedown"))
    })

    await act(() => vi.advanceTimersByTime(50))

    expect(result.current).toBeTruthy()

    await act(() => {
      document.dispatchEvent(new Event("wheel"))
    })

    await act(() => vi.advanceTimersByTime(50))

    expect(result.current).toBeTruthy()
  })
})

"use client"

import { useEffect, useRef, useState } from "react"

const DEFAULT_EVENTS: (keyof DocumentEventMap)[] = [
  "keypress",
  "mousemove",
  "touchmove",
  "click",
  "scroll",
]

const DEFAULT_OPTIONS = {
  events: DEFAULT_EVENTS,
  initialState: true,
}

export interface IdleOptions {
  events?: (keyof DocumentEventMap)[]
  initialState?: boolean
}

/**
 * `useIdle` is a custom hook that detects whether the user has been idle for a certain amount of time in milliseconds.
 *
 * @see https://yamada-ui.com/docs/hooks/use-idle
 */
export const useIdle = (timeout: number, options?: IdleOptions) => {
  const { events, initialState } = { ...DEFAULT_OPTIONS, ...options }
  const [idle, setIdle] = useState<boolean>(initialState)
  const timeoutId = useRef<NodeJS.Timeout>(undefined)

  useEffect(() => {
    const handleEvent = () => {
      setIdle(false)

      if (timeoutId.current) clearTimeout(timeoutId.current)

      timeoutId.current = setTimeout(() => setIdle(true), timeout)
    }

    events.forEach((event) => document.addEventListener(event, handleEvent))

    return () => {
      events.forEach((event) =>
        document.removeEventListener(event, handleEvent),
      )
    }
  }, [events, timeout])

  return idle
}
